SELECT l.*, tpl.template_nm AS template_nm, ste.site_nm AS site_nm, cd_pc.code_label AS channel_cd_nm, cd_pr.code_label AS result_cd_nm FROM cmh_push_log l LEFT JOIN sy_template tpl ON tpl.template_id = l.template_id LEFT JOIN sy_site ste ON ste.site_id = l.site_id LEFT JOIN sy_code cd_pc ON cd_pc.code_grp = 'PUSH_CHANNEL' AND cd_pc.code_value = l.channel_cd LEFT JOIN sy_code cd_pr ON cd_pr.code_grp = 'PUSH_RESULT' AND cd_pr.code_value = l.result_cd
ORDER BY l.log_id ASC ORDER BY l.log_id DESC ORDER BY l.push_log_title ASC ORDER BY l.push_log_title DESC ORDER BY l.send_date ASC ORDER BY l.send_date DESC ORDER BY l.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT l.*, tpl.template_nm AS template_nm, ste.site_nm AS site_nm, cd_pc.code_label AS channel_cd_nm, cd_pr.code_label AS result_cd_nm FROM cmh_push_log l LEFT JOIN sy_template tpl ON tpl.template_id = l.template_id LEFT JOIN sy_site ste ON ste.site_id = l.site_id LEFT JOIN sy_code cd_pc ON cd_pc.code_grp = 'PUSH_CHANNEL' AND cd_pc.code_value = l.channel_cd LEFT JOIN sy_code cd_pr ON cd_pr.code_grp = 'PUSH_RESULT' AND cd_pr.code_value = l.result_cd
ORDER BY l.log_id ASC ORDER BY l.log_id DESC ORDER BY l.push_log_title ASC ORDER BY l.push_log_title DESC ORDER BY l.send_date ASC ORDER BY l.send_date DESC ORDER BY l.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}
